from __future__ import annotations
import ast
import io
import json
import os
import re
import contextlib
from dataclasses import dataclass, field
from typing import Optional
from openai import OpenAI

client = OpenAI(api_key=os.environ['OPENAI_API_KEY'])
MODEL = 'gpt-4o'  # use GPT-4o for code tasks


# ── Sandbox executor ──────────────────────────────────────────────────────────

@dataclass
class ExecutionResult:
    stdout: str
    stderr: str
    success: bool
    test_results: Optional[dict] = None

    def summary(self) -> str:
        parts = []
        if self.stdout:
            parts.append(f'Output:\n{self.stdout}')
        if self.stderr:
            parts.append(f'Errors:\n{self.stderr}')
        if self.test_results:
            tr = self.test_results
            parts.append(f'Tests: {tr["passed"]}/{tr["total"]} passed')
        return '\n'.join(parts) or '(no output)'


SAFE_BUILTINS = {
    'print': print, 'range': range, 'len': len, 'sum': sum, 'sorted': sorted,
    'max': max, 'min': min, 'abs': abs, 'round': round, 'enumerate': enumerate,
    'zip': zip, 'list': list, 'dict': dict, 'set': set, 'tuple': tuple,
    'str': str, 'int': int, 'float': float, 'bool': bool, 'type': type,
    'isinstance': isinstance, 'hasattr': hasattr, 'getattr': getattr,
    'map': map, 'filter': filter, 'any': any, 'all': all,
    'Exception': Exception, 'ValueError': ValueError, 'TypeError': TypeError,
    'AssertionError': AssertionError,
    '__builtins__': {},
}

ALLOWED_IMPORTS = {'math', 'random', 'collections', 'itertools', 'functools', 'heapq', 'bisect'}


def extract_imports(code: str) -> set[str]:
    tree = ast.parse(code)
    imports = set()
    for node in ast.walk(tree):
        if isinstance(node, (ast.Import, ast.ImportFrom)):
            if isinstance(node, ast.Import):
                imports.update(alias.name.split('.')[0] for alias in node.names)
            else:
                if node.module:
                    imports.add(node.module.split('.')[0])
    return imports


def execute_code(code: str, timeout: int = 10) -> ExecutionResult:
    # 1. Syntax check
    try:
        tree = ast.parse(code)
    except SyntaxError as e:
        return ExecutionResult(stdout='', stderr=f'SyntaxError at line {e.lineno}: {e.msg}', success=False)

    # 2. Import safety check
    imports = extract_imports(code)
    blocked = imports - ALLOWED_IMPORTS
    if blocked:
        return ExecutionResult(stdout='', stderr=f'Blocked imports: {blocked}. Allowed: {ALLOWED_IMPORTS}', success=False)

    # 3. Execute in restricted namespace
    namespace = {**SAFE_BUILTINS}
    for mod_name in imports:
        import importlib
        namespace[mod_name] = importlib.import_module(mod_name)

    stdout_buf = io.StringIO()
    stderr_buf = io.StringIO()
    try:
        with contextlib.redirect_stdout(stdout_buf):
            exec(code, namespace)  # noqa: S102
        return ExecutionResult(stdout=stdout_buf.getvalue(), stderr='', success=True)
    except AssertionError as e:
        failures = str(e)
        return ExecutionResult(stdout=stdout_buf.getvalue(), stderr=f'AssertionError: {failures}', success=False)
    except Exception as e:
        return ExecutionResult(stdout=stdout_buf.getvalue(), stderr=f'{type(e).__name__}: {e}', success=False)


def run_tests(code: str, test_code: str) -> ExecutionResult:
    """Run tests against the generated code."""
    full_code = code + '\n\n' + test_code
    result = execute_code(full_code)

    # Count assertions
    total = test_code.count('assert ')
    if result.success:
        return ExecutionResult(
            stdout=result.stdout, stderr='', success=True,
            test_results={'passed': total, 'total': total, 'failed': 0}
        )
    else:
        # Try to count which test failed
        failed_line = re.search(r'AssertionError.*', result.stderr)
        return ExecutionResult(
            stdout=result.stdout, stderr=result.stderr, success=False,
            test_results={'passed': 0, 'total': total, 'failed': total, 'error': result.stderr}
        )


# ── Code agent ────────────────────────────────────────────────────────────────

CODE_SYSTEM = """You are an expert Python programmer. Write clean, correct code.
Only use Python standard library modules from: math, random, collections, itertools, functools, heapq, bisect.
Do not use imports outside this list. Do not use file I/O or network calls.
Always include type hints. Return only code in a ```python ... ``` block."""

TEST_SYSTEM = """You are writing unit tests for Python functions.
Write assertions using the `assert` statement (no pytest or unittest — just raw asserts).
Test normal cases, edge cases, and error cases.
Return only test code in a ```python ... ``` block."""


def extract_code_block(text: str) -> str:
    match = re.search(r'```python\n(.*?)```', text, re.DOTALL)
    return match.group(1).strip() if match else text.strip()


def llm_generate_code(prompt: str, system: str = CODE_SYSTEM) -> str:
    response = client.chat.completions.create(
        model=MODEL,
        messages=[{'role': 'system', 'content': system}, {'role': 'user', 'content': prompt}],
        temperature=0.2,
    )
    return extract_code_block(response.choices[0].message.content)


def llm_fix_code(code: str, error: str, task: str) -> str:
    prompt = f"""This code has an error. Fix it.

Task: {task}

Code:
```python
{code}
```

Error:
{error}

Provide only the corrected code in a ```python ... ``` block."""
    return extract_code_block(client.chat.completions.create(
        model=MODEL,
        messages=[{'role': 'user', 'content': prompt}],
        temperature=0,
    ).choices[0].message.content)


@dataclass
class CodeAgentResult:
    task: str
    final_code: str
    test_code: str
    iterations: int
    test_passed: bool
    execution_result: ExecutionResult


class CodeAgent:
    def __init__(self, max_fix_attempts: int = 3, tdd_mode: bool = True):
        self.max_fix_attempts = max_fix_attempts
        self.tdd_mode = tdd_mode

    def run(self, task: str) -> CodeAgentResult:
        print(f'Task: {task}')

        # Step 1: Generate tests (TDD mode)
        if self.tdd_mode:
            print('  Generating tests first (TDD)...')
            test_code = llm_generate_code(
                f'Write unit tests (using only assert statements) for this function: {task}',
                system=TEST_SYSTEM,
            )
            print(f'  Tests generated ({test_code.count("assert")} assertions)')
        else:
            test_code = ''

        # Step 2: Generate initial code
        print('  Generating code...')
        code = llm_generate_code(task)

        # Step 3: Execute and fix loop
        for attempt in range(self.max_fix_attempts + 1):
            if self.tdd_mode:
                result = run_tests(code, test_code)
            else:
                result = execute_code(code)

            if result.success:
                print(f'  ✓ Tests passed on attempt {attempt + 1}')
                return CodeAgentResult(
                    task=task, final_code=code, test_code=test_code,
                    iterations=attempt + 1, test_passed=True, execution_result=result,
                )

            if attempt < self.max_fix_attempts:
                print(f'  ✗ Attempt {attempt + 1} failed: {result.stderr[:60]}...')
                print(f'  → Fixing...')
                code = llm_fix_code(code, result.summary(), task)

        print(f'  ✗ Failed after {self.max_fix_attempts + 1} attempts')
        return CodeAgentResult(
            task=task, final_code=code, test_code=test_code,
            iterations=self.max_fix_attempts + 1, test_passed=False, execution_result=result,
        )


# ── Demo ──────────────────────────────────────────────────────────────────────

if __name__ == '__main__':
    agent = CodeAgent(max_fix_attempts=3, tdd_mode=True)

    tasks = [
        'Write a function fibonacci(n: int) -> list[int] that returns the first n Fibonacci numbers.',
        'Write a function is_palindrome(s: str) -> bool that ignores case and non-alphanumeric characters.',
        'Write a function two_sum(nums: list[int], target: int) -> list[int] that returns indices of two numbers that add to target.',
    ]

    for task in tasks:
        print(f'\n{"-"*60}')
        result = agent.run(task)
        print(f'\nResult: {"PASSED" if result.test_passed else "FAILED"} ({result.iterations} iteration(s))')
        if result.test_passed:
            print(f'Final code:\n{result.final_code}')

