import ast

ALLOWED_IMPORTS = {'math', 'random', 'collections', 'itertools'}

def is_safe_code(code: str) -> tuple[bool, str]:
    try:
        tree = ast.parse(code)
    except SyntaxError as e:
        return False, f'SyntaxError: {e}'

    for node in ast.walk(tree):
        if isinstance(node, ast.Import):
            for alias in node.names:
                mod = alias.name.split('.')[0]
                if mod not in ALLOWED_IMPORTS:
                    return False, f'Blocked import: {mod}'
        elif isinstance(node, ast.ImportFrom):
            if node.module and node.module.split('.')[0] not in ALLOWED_IMPORTS:
                return False, f'Blocked import from: {node.module}'
    return True, 'safe'
```
Using `ast.parse` is more reliable than string matching — `import\nos` would fool a simple string check but not AST analysis.
